const job = $input.item.json;
const rawUrl = job.jobUrl || job.url || job.applyUrl || job.link || '';
const url = rawUrl.split('?')[0];
const id = Buffer.from(url || job.id || '').toString('base64').replace(/[^a-zA-Z0-9]/g, '').slice(0, 32);
const company = (job.company && (job.company.name || job.company)) || job.companyName || '';
return {
  id,
  title: job.title || job.jobTitle || '',
  company,
  location: job.location || job.formattedLocation || job.city || '',
  description: (job.description || job.shortDescription || job.snippet || '').slice(0, 1500),
  url,
  posted_date: job.listedAt || job.postedAt || job.datePosted || '',
  source: 'LinkedIn'
};

const all = $input.all();
// GSheets rows haben job_id; Job-Items haben source-Feld
const seen = new Set(
  all.filter(i => !i.json.source && i.json.job_id).map(i => String(i.json.job_id))
);
const inRun = new Set();
const result = [];
for (const item of all) {
  const {source, id} = item.json;
  if (!source || !id) continue;  // GSheets-Zeilen überspringen
  if (seen.has(id) || inRun.has(id)) continue;  // Duplikate entfernen
  inRun.add(id);
  result.push(item);
}
result.sort((a, b) => (a.json.title || '').localeCompare(b.json.title || ''));
return result;

const POSITIVE = {'GKV': 20, 'gesetzliche Krankenversicherung': 20, 'Krankenkasse': 18, 'Krankenkassen': 18, 'BKK': 15, 'IKK': 15, 'DAK': 15, 'AOK': 15, 'Public Sector': 15, 'offentlicher Sektor': 10, 'Account Manager': 15, 'Sales Manager': 15, 'Key Account': 15, 'Business Development': 12, 'Vertrieb': 10, 'eHealth': 15, 'Gesundheitswesen': 12, 'Healthcare IT': 15, 'Health IT': 15, 'IT-Consulting': 12, 'Digital Health': 14, 'Digitalisierung': 8, 'Ausschreibung': 15, 'Vergabe': 12, 'BAFO': 15, 'Tender': 10, 'KRITIS': 12, 'NIS2': 12, 'SGB V': 15, 'TI 2.0': 12, 'Telematikinfrastruktur': 12, 'BITMARCK': 15, 'Senior': 8, 'Director': 5, 'Head of': 5, 'Hamburg': 5, 'Remote': 5, 'Hybrid': 5, 'CDO': 15, 'Chief Digital Officer': 22, 'Leiter Digital': 22, 'msg': 8, 'Sopra Steria': 8, 'Capgemini': 8, 'T-Systems': 8, 'CGI': 8, 'Leiter Vertrieb': 20, 'Leiter Innovation': 20, 'Leiter Einkauf': 20};
const NEGATIVE = {'INIT AG': -100, 'adesso SE': -100, 'Zeitarbeit': -30, 'Werkstudent': -40, 'Praktikum': -40, 'Trainee': -20, 'Junior': -25, 'Berufseinsteiger': -30, 'Minijob': -40, 'Pflegekraft': -40, 'Pflegefachkraft': -40, 'Arzt': -40, 'Medizin': -20, 'Produktion': -30, 'Logistik': -20, 'Fahrer': -35, 'Hausmeister': -40, 'Reinigung': -40};
const item = $input.item.json;
if (!item.title) return null;
const text = [item.title, item.description || '', item.company || '', item.location || ''].join(' ').toLowerCase();
let score = 0;
for (const [kw, pts] of Object.entries(POSITIVE)) { if (text.includes(kw.toLowerCase())) score += pts; }
for (const [kw, pen] of Object.entries(NEGATIVE)) { if (text.includes(kw.toLowerCase())) score += pen; }
return {...$input.item.json, keyword_score: Math.max(0, Math.min(100, score))};

