const item = $input.item.json;
try {
  let raw = item.content[0].text.trim();
  if (raw.startsWith('```')) {
    raw = raw.split('\n').slice(1).join('\n').replace(/```$/, '').trim();
  }
  const result = JSON.parse(raw);
  const score = Math.max(0, Math.min(100, parseInt(result.score) || 0));
  const emoji = score >= 70 ? '\uD83D\uDFE2' : score >= 40 ? '\uD83D\uDFE1' : '\uD83D\uDD35';
  return {
    ...item,
    ai_score: score,
    ai_reason: result.reason || '',
    ai_strengths: result.strengths || [],
    ai_concerns: result.concerns || [],
    ai_action: result.action || '',
    score_emoji: emoji
  };
} catch(e) {
  return { ...item, ai_score: item.keyword_score || 0, ai_reason: '', ai_strengths: [], ai_concerns: [], ai_action: '', score_emoji: '\uD83D\uDD35' };
}

const jobs = ($input.item.json.jobs || []).filter(j => (j.ai_score || 0) >= 25);
jobs.sort((a, b) => (b.ai_score || 0) - (a.ai_score || 0));
if (jobs.length === 0) return null;
const today = new Date().toLocaleDateString('de-DE', {day:'2-digit', month:'2-digit', year:'numeric'});
const SRC_COLORS = {'Arbeitsagentur': '#005b99', 'LinkedIn': '#0077b5', 'Indeed': '#2557a7'};
function sc(s) { return s >= 70 ? '#16a34a' : s >= 50 ? '#65a30d' : s >= 35 ? '#d97706' : '#2563eb'; }
function sl(s) { return s >= 70 ? 'Top' : s >= 50 ? 'Hoch' : s >= 35 ? 'Mittel' : 'Ok'; }
const rows = jobs.map(job => {
  const s = job.ai_score || 0;
  const ac = job.ai_action === 'Sofort bewerben' ? 'background:#16a34a;color:#fff' : job.ai_action === 'Pruefen' ? 'background:#d97706;color:#fff' : 'background:#e5e7eb;color:#6b7280';
  const str = (job.ai_strengths || []).map(x => `<span style='background:#dcfce7;color:#166534;border-radius:3px;padding:2px 5px;font-size:10px'>✓ ${x}</span>`).join(' ');
  const con = (job.ai_concerns || []).map(x => `<span style='background:#fff7ed;color:#9a3412;border-radius:3px;padding:2px 5px;font-size:10px'>⚠ ${x}</span>`).join(' ');
  return `<tr style='border-bottom:1px solid #e5e7eb'><td style='padding:10px 8px 10px 0;vertical-align:top;white-space:nowrap;width:1%'><div style='background:${sc(s)};color:#fff;border-radius:6px;padding:4px 8px;text-align:center;min-width:48px'><div style='font-size:14px;font-weight:800'>${s}</div><div style='font-size:9px;opacity:.9'>${sl(s)}</div></div></td><td style='padding:10px 12px;vertical-align:top'><div style='font-size:14px;font-weight:700;color:#111827'>${job.title}</div><div style='font-size:12px;color:#374151;margin-top:2px'>${job.company || '—'}</div><div style='font-size:11px;color:#6b7280;margin-top:2px'>📍 ${job.location} <span style='background:${SRC_COLORS[job.source] || '#6b7280'};color:#fff;border-radius:3px;padding:1px 5px;font-size:9px'>${job.source}</span></div>${job.ai_reason ? `<div style='margin-top:5px;font-size:11px;color:#6366f1;font-style:italic'>🤖 ${job.ai_reason}</div>` : ''}${str ? `<div style='margin-top:3px'>${str}</div>` : ''}${con ? `<div style='margin-top:2px'>${con}</div>` : ''}${job.ai_action ? `<div style='margin-top:4px'><span style='${ac};border-radius:4px;padding:2px 7px;font-size:9px;font-weight:700'>${job.ai_action}</span></div>` : ''}</td><td style='padding:10px 0 10px 8px;vertical-align:middle;white-space:nowrap;width:1%'><a href='${job.url}' style='display:inline-block;background:#2563eb;color:#fff;padding:7px 12px;border-radius:6px;text-decoration:none;font-size:12px;font-weight:600'>Bewerben →</a></td></tr>`;
}).join('');
const src = {}; jobs.forEach(j => { src[j.source] = (src[j.source] || 0) + 1; });
const srcStr = Object.entries(src).map(([s,n]) => `${s}: ${n}`).join(' · ');
const html = `<!DOCTYPE html><html lang='de'><head><meta charset='UTF-8'></head><body style='margin:0;padding:0;background:#f3f4f6;font-family:-apple-system,sans-serif'><div style='max-width:680px;margin:0 auto;padding:24px 16px'><div style='background:linear-gradient(135deg,#1e3a8a,#2563eb);border-radius:14px;padding:22px 26px;margin-bottom:18px'><h1 style='margin:0 0 4px;font-size:19px;color:#fff;font-weight:800'>🔍 Deine Stellen-Übersicht — ${today}</h1><p style='margin:0;font-size:12px;color:#bfdbfe'><strong style='color:#fff'>${jobs.length} relevante Stelle${jobs.length !== 1 ? 'n' : ''}</strong> · ${srcStr}</p></div><div style='background:#fff;border-radius:12px;padding:6px 18px 2px;box-shadow:0 1px 4px rgba(0,0,0,.07);border:1px solid #e5e7eb'><table style='width:100%;border-collapse:collapse'>${rows}</table></div></div></body></html>`;
return { htmlContent: html, jobCount: jobs.length, subject: `🔍 ${jobs.length} neue Stellen | ${today}` };
